module.exports = {
  config: {
cooldowns: 10,
premium: false,
permission: 0,
    name: "virustext",
    aliases: ["zalgo"],
    version: "1.0.0",
    credits: "Raza",
    description: "Converts your text to Zalgo",
    category: "font",
    usage: "zalgo <text>",
    prefix: true
  },

  async run({ api, event, args, send }) {
    const Zalgo = require("to-zalgo");
    const text = args.join(" ");
    if (!text) return send.reply("━❮🐉❯━━━❪💝❫━━━❮🐉❯━\n❌ 🅟𝐥𝐞𝐚𝐬𝐞 𝐞𝐧𝐭𝐞𝐫 𝐬𝐨𝐦𝐞 𝐭𝐞𝐱𝐭 𝐭𝐨 𝐜𝐨𝐧𝐯𝐞𝐫𝐭.\n━❮🐉❯━━━❪💝❫━━━❮🐉❯━");
    return send.reply(Zalgo(text));
  }
};
